const apiResponse = $('API: Lineup abrufen9').first().json;
const matchId = $('Webhook Lineup8').first().json.body.match_id;

if (!apiResponse.response || apiResponse.response.length === 0) return [];

const items = [];

apiResponse.response.forEach(teamData => {
  const formation = teamData.formation;

  const players = [
    ...teamData.startXI.map(p => ({ ...p.player, is_substitute: false })),
    ...teamData.substitutes.map(p => ({ ...p.player, is_substitute: true }))
  ];

  players.forEach(p => {
    items.push({ json: {
      match_id: matchId,
      team_external_id: teamData.team.id,
      formation,
      player_external_id: p.id,
      player_name: p.name || null,
      jersey_number: p.number || null,
      status: p.is_substitute ? 'Sub' : 'Start',
      position: p.pos || null,
      is_substituted: false
    }});
  });

  if (teamData.coach?.name) {
    items.push({ json: {
      match_id: matchId,
      team_external_id: teamData.team.id,
      formation,
      player_external_id: null,
      player_name: teamData.coach.name,
      jersey_number: null,
      status: 'Coach',
      position: null,
      is_substituted: false
    }});
  }
});

return items;
